/**
 * AURA ALPHA — Backtest Upgrade Modal
 *
 * Conversion modal shown when a user hits a tier-gated backtest limit.
 * Dark glass morphism design matching TierGate.jsx patterns.
 */
import { useNavigate } from 'react-router-dom';
import { tokens } from '../styles/tokens';
import { AURA_TIERS } from '../config/pricing';

const T = {
  text: tokens.color.text,
  textSec: tokens.color.textSecondary,
  green: tokens.color.green,
  purple: tokens.color.purple,
  blue: tokens.color.blue,
  amber: tokens.color.amber,
  border: tokens.color.border,
  surface2: tokens.color.surfaceHover,
  mono: tokens.font.mono,
  sans: tokens.font.sans,
};

const TIER_COLORS = {
  trader: T.green,
  pro: T.purple,
  elite: T.amber,
  institutional: '#E0E0E0',
};

const FEATURE_COPY = {
  strategy: {
    heading: 'Unlock All Strategies',
    body: 'Access all 83 signal detection systems. More strategies means more opportunities to compound your capital across market conditions.',
  },
  symbol: {
    heading: 'Expand Your Universe',
    body: 'Backtest against a broader symbol universe. Broader coverage means you never miss an edge forming in secondary equities.',
  },
  timeframe: {
    heading: 'Unlock Extended History',
    body: 'Longer backtests reveal how strategies survive recessions, crashes, and regime changes. Real edge is proven across full market cycles.',
  },
  batch: {
    heading: 'Batch Backtesting',
    body: 'Run multiple strategies simultaneously across your entire watchlist. Identify the highest-conviction systems in a fraction of the time.',
  },
  optimize: {
    heading: 'Parameter Optimization',
    body: 'Systematically optimize entry/exit parameters to maximize risk-adjusted returns. Find the exact configuration that compounds capital fastest.',
  },
  runs: {
    heading: 'More Backtest Runs',
    body: 'You have used all your backtest runs for today. Upgrade for higher limits and never wait to validate a trading idea.',
  },
};

const TIER_LABELS = {
  trader: 'Trader',
  pro: 'Pro',
  elite: 'Elite',
  institutional: 'Institutional',
};

export default function BacktestUpgradeModal({ open, onClose, feature, detail, upgradeTier }) {
  const navigate = useNavigate();

  if (!open) return null;

  const tierKey = upgradeTier || 'pro';
  const color = TIER_COLORS[tierKey] || T.purple;
  const label = TIER_LABELS[tierKey] || 'Pro';
  const price = AURA_TIERS[tierKey]?.price || 129;
  const copy = FEATURE_COPY[feature] || FEATURE_COPY.strategy;

  return (
    <>
      {/* Overlay */}
      <div
        onClick={onClose}
        style={{
          position: 'fixed', inset: 0, zIndex: 9998,
          background: 'rgba(0,0,0,0.65)',
          backdropFilter: 'blur(6px)',
          WebkitBackdropFilter: 'blur(6px)',
        }}
      />

      {/* Modal */}
      <div style={{
        position: 'fixed', inset: 0, zIndex: 9999,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        pointerEvents: 'none',
      }}>
        <div style={{
          pointerEvents: 'auto',
          maxWidth: 420, width: '90vw',
          background: 'linear-gradient(135deg, rgba(11,15,20,0.97), rgba(15,22,32,0.97))',
          backdropFilter: 'blur(20px)',
          WebkitBackdropFilter: 'blur(20px)',
          border: `1px solid ${color}22`,
          borderRadius: 16,
          padding: '36px 32px 28px',
          textAlign: 'center',
          boxShadow: `0 8px 40px rgba(0,0,0,0.5), 0 0 60px ${color}10`,
        }}>
          {/* Lock icon */}
          <div style={{
            width: 56, height: 56, borderRadius: 14,
            margin: '0 auto 20px',
            background: `${color}12`,
            border: `2px solid ${color}30`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke={color} strokeWidth="2">
              <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
              <path d="M7 11V7a5 5 0 0110 0v4" />
            </svg>
          </div>

          {/* Heading */}
          <h2 style={{
            fontSize: 20, fontWeight: 700, color: T.text,
            fontFamily: T.sans, margin: '0 0 8px',
          }}>
            {copy.heading}
          </h2>

          {/* Detail (the specific thing they tried) */}
          {detail && (
            <div style={{
              display: 'inline-block',
              padding: '4px 12px', borderRadius: 6,
              background: `${color}12`, border: `1px solid ${color}25`,
              fontFamily: T.mono, fontSize: 12, fontWeight: 600,
              color, marginBottom: 12,
            }}>
              {detail}
            </div>
          )}

          {/* Value explanation */}
          <p style={{
            fontSize: 13, color: T.textSec, lineHeight: 1.6,
            margin: '0 0 24px', fontFamily: T.sans,
          }}>
            {copy.body}
          </p>

          {/* Price badge */}
          <div style={{ marginBottom: 16 }}>
            <span style={{
              fontFamily: T.mono, fontSize: 28, fontWeight: 800, color,
            }}>
              ${price}
            </span>
            <span style={{ fontSize: 14, color: T.textSec, marginLeft: 4 }}>/mo</span>
          </div>

          {/* Primary CTA */}
          <button
            onClick={() => { onClose(); navigate('/pricing-plans'); }}
            style={{
              display: 'block', width: '100%',
              padding: '12px 24px', borderRadius: 10,
              fontSize: 14, fontWeight: 700,
              fontFamily: T.mono, color: '#fff',
              border: 'none', cursor: 'pointer',
              background: `linear-gradient(135deg, ${color}, ${color}CC)`,
              boxShadow: `0 4px 20px ${color}33`,
              marginBottom: 12,
              transition: 'filter 150ms ease',
            }}
            onMouseEnter={e => e.currentTarget.style.filter = 'brightness(1.15)'}
            onMouseLeave={e => e.currentTarget.style.filter = 'brightness(1)'}
          >
            Upgrade to {label}
          </button>

          {/* Secondary CTA */}
          <button
            onClick={onClose}
            style={{
              display: 'block', width: '100%',
              padding: '10px 24px', borderRadius: 10,
              fontSize: 13, fontWeight: 600,
              fontFamily: T.sans, color: T.textSec,
              background: 'transparent',
              border: `1px solid ${T.border}`,
              cursor: 'pointer',
              transition: 'border-color 150ms ease',
            }}
            onMouseEnter={e => e.currentTarget.style.borderColor = color + '44'}
            onMouseLeave={e => e.currentTarget.style.borderColor = T.border}
          >
            Continue with current plan
          </button>
        </div>
      </div>
    </>
  );
}
