/**
 * AURA ALPHA — Backtest Feature Gates
 *
 * Tier-aware gating for backtest configuration.
 * Free tier: 10 strategies, top 50 symbols, 2yr max, 5 runs/session
 * Trader: 25 strategies, 200 symbols, 5yr, 50 runs
 * Pro+: unlimited
 */
import { getUserTier, TIER_LEVELS } from '../hooks/useTierGate';
import { STRATEGY_LIMITS, BACKTEST_LIMITS } from '../config/pricing';

const TIER_BACKTEST_CONFIG = {
  explorer:      { strategies: 10, symbols: 50,  maxYears: 2,  runsPerSession: 5,   batch: false, optimize: false },
  trader:        { strategies: 25, symbols: 200, maxYears: 5,  runsPerSession: 50,  batch: false, optimize: false },
  pro:           { strategies: 999, symbols: 999, maxYears: 30, runsPerSession: 999, batch: true,  optimize: true },
  institutional: { strategies: 999, symbols: 999, maxYears: 30, runsPerSession: 999, batch: true,  optimize: true },
};

// Top 50 free symbols (major US equities)
const FREE_SYMBOLS = [
  'AAPL','MSFT','GOOGL','AMZN','NVDA','META','TSLA','BRK.B','UNH','JNJ',
  'V','XOM','JPM','MA','PG','HD','AVGO','CVX','MRK','LLY',
  'ABBV','COST','PEP','KO','PFE','WMT','TMO','CSCO','MCD','CRM',
  'ABT','ACN','ADBE','AMD','DHR','TXN','NEE','NFLX','INTC','BA',
  'DIS','CAT','GE','SBUX','RTX','DE','SYK','QCOM','PYPL','SPY',
];

// Top 10 free strategies
const FREE_STRATEGIES = [
  'breakout','bullish_pullback','momentum_surge','oversold_rsi_bounce',
  'double_bottom','ema_cloud_long','hammer_reversal','cup_and_handle',
  'inside_bar_breakout','trend_play',
];

export function getBacktestConfig() {
  const tier = getUserTier();
  return TIER_BACKTEST_CONFIG[tier] || TIER_BACKTEST_CONFIG.explorer;
}

export function canUseStrategy(strategy) {
  const tier = getUserTier();
  if (TIER_LEVELS[tier] >= TIER_LEVELS.pro) return { allowed: true };
  const normalized = (strategy || '').toLowerCase().replace(/[\s\-]+/g, '_');
  const allowed = FREE_STRATEGIES.includes(normalized);
  return {
    allowed,
    reason: allowed ? null : 'pro',
    upgrade: 'Unlock all 83 strategies with Pro',
  };
}

export function canUseSymbol(symbol) {
  const tier = getUserTier();
  if (TIER_LEVELS[tier] >= TIER_LEVELS.trader) return { allowed: true };
  const upper = (symbol || '').toUpperCase();
  const allowed = FREE_SYMBOLS.includes(upper);
  return {
    allowed,
    reason: allowed ? null : 'trader',
    upgrade: `${upper} requires Trader tier or above`,
  };
}

export function canUseTimeframe(years) {
  const config = getBacktestConfig();
  const allowed = years <= config.maxYears;
  return {
    allowed,
    reason: allowed ? null : 'pro',
    upgrade: `Backtests beyond ${config.maxYears} years require Pro`,
  };
}

export function canRunBatch() {
  const config = getBacktestConfig();
  return {
    allowed: config.batch,
    reason: config.batch ? null : 'pro',
    upgrade: 'Batch backtesting requires Pro',
  };
}

export function canOptimize() {
  const config = getBacktestConfig();
  return {
    allowed: config.optimize,
    reason: config.optimize ? null : 'pro',
    upgrade: 'Parameter optimization requires Pro',
  };
}

export function getRemainingRuns() {
  const config = getBacktestConfig();
  const key = 'aura_bt_runs_' + new Date().toISOString().slice(0, 10);
  const used = parseInt(localStorage.getItem(key) || '0', 10);
  return {
    remaining: Math.max(0, config.runsPerSession - used),
    limit: config.runsPerSession,
    used,
  };
}

export function recordRun() {
  const key = 'aura_bt_runs_' + new Date().toISOString().slice(0, 10);
  const used = parseInt(localStorage.getItem(key) || '0', 10);
  localStorage.setItem(key, String(used + 1));
}

export { FREE_SYMBOLS, FREE_STRATEGIES, TIER_BACKTEST_CONFIG };
