/* ═══════════════════════════════════════════════════════════════
   EQUITY CURVE SVG
   ═══════════════════════════════════════════════════════════════ */
function EquityCurveSVG({ data, startVal }) {
  if (!data || data.length < 2) return null;
  const w = 800, h = 120, padY = 6, labelW = 60;
  const min = Math.min(...data), max = Math.max(...data);
  const range = max - min || 1;
  const last = data[data.length - 1];
  const lineColor = last >= startVal ? C.green : C.red;
  const yForVal = (v) => padY + (1 - (v - min) / range) * (h - padY * 2);
  const points = data.map((v, i) => {
    const x = labelW + (i / (data.length - 1)) * (w - labelW);
    return `${x},${yForVal(v)}`;
  }).join(' ');
  return (
    <svg viewBox={`0 0 ${w} ${h}`} style={{ width: '100%', height: h }}>
      <defs>
        <linearGradient id="runnerEqGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={lineColor} stopOpacity="0.2" />
          <stop offset="100%" stopColor={lineColor} stopOpacity="0" />
        </linearGradient>
      </defs>
      <text x={labelW - 6} y={yForVal(max) + 4} textAnchor="end" fill={C.textSecondary} fontSize="8" fontFamily="var(--font-mono)">{fmtDollar(max)}</text>
      <text x={labelW - 6} y={yForVal(min) + 4} textAnchor="end" fill={C.textSecondary} fontSize="8" fontFamily="var(--font-mono)">{fmtDollar(min)}</text>
      <text x={labelW - 6} y={yForVal(last) + 4} textAnchor="end" fill={lineColor} fontSize="8" fontWeight="700" fontFamily="var(--font-mono)">{fmtDollar(last)}</text>
      <line x1={labelW} y1={yForVal(startVal)} x2={w} y2={yForVal(startVal)} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
      <polygon points={`${labelW},${yForVal(startVal)} ${points} ${w},${yForVal(startVal)}`} fill="url(#runnerEqGrad)" />
      <polyline points={points} fill="none" stroke={lineColor} strokeWidth="1.5" strokeLinejoin="round" />
    </svg>
  );
}

/* ═══════════════════════════════════════════════════════════════
   COMPARE EQUITY CURVE SVG (two overlaid curves)
   ═══════════════════════════════════════════════════════════════ */
function CompareEquityCurveSVG({ dataA, dataB, labelA, labelB, startVal }) {
  if ((!dataA || dataA.length < 2) && (!dataB || dataB.length < 2)) return null;
  const w = 800, h = 160, padY = 10, labelW = 60;
  const allVals = [...(dataA || []), ...(dataB || [])];
  const min = Math.min(...allVals), max = Math.max(...allVals);
  const range = max - min || 1;
  const yForVal = (v) => padY + (1 - (v - min) / range) * (h - padY * 2);

  const makeLine = (data) => {
    if (!data || data.length < 2) return '';
    return data.map((v, i) => {
      const x = labelW + (i / (data.length - 1)) * (w - labelW);
      return `${x},${yForVal(v)}`;
    }).join(' ');
  };

  const pointsA = makeLine(dataA);
  const pointsB = makeLine(dataB);
  const lastA = dataA && dataA.length > 0 ? dataA[dataA.length - 1] : null;
  const lastB = dataB && dataB.length > 0 ? dataB[dataB.length - 1] : null;
  const colorA = C.blue;
  const colorB = C.purple;

  return (
    <div className={s.compareCurveCard}>
      <div className={s.compareCurveHeader}>
        <div className={s.compareCurveTitle}>Strategy Comparison</div>
        <div className={s.legendRow}>
          <div className={s.legendItem}>
            <div className={s.legendSwatch} style={{ background: colorA }} />
            <span className={s.legendLabel} style={{ color: colorA }}>{labelA}</span>
          </div>
          <div className={s.legendItem}>
            <div className={s.legendSwatch} style={{ background: colorB }} />
            <span className={s.legendLabel} style={{ color: colorB }}>{labelB}</span>
          </div>
        </div>
      </div>
      <svg viewBox={`0 0 ${w} ${h}`} style={{ width: '100%', height: h }}>
        <text x={labelW - 6} y={yForVal(max) + 4} textAnchor="end" fill={C.textSecondary} fontSize="8" fontFamily="var(--font-mono)">{fmtDollar(max)}</text>
        <text x={labelW - 6} y={yForVal(min) + 4} textAnchor="end" fill={C.textSecondary} fontSize="8" fontFamily="var(--font-mono)">{fmtDollar(min)}</text>
        <line x1={labelW} y1={yForVal(startVal)} x2={w} y2={yForVal(startVal)} stroke={C.border} strokeWidth="0.5" strokeDasharray="3,3" />
        {pointsA && <polyline points={pointsA} fill="none" stroke={colorA} strokeWidth="1.5" strokeLinejoin="round" />}
        {pointsB && <polyline points={pointsB} fill="none" stroke={colorB} strokeWidth="1.5" strokeLinejoin="round" strokeDasharray="4,2" />}
        {lastA != null && (
          <text x={w - 4} y={yForVal(lastA) - 4} textAnchor="end" fill={colorA} fontSize="9" fontWeight="700" fontFamily="var(--font-mono)">
            {fmtDollar(lastA)}
          </text>
        )}
        {lastB != null && (
          <text x={w - 4} y={yForVal(lastB) + 12} textAnchor="end" fill={colorB} fontSize="9" fontWeight="700" fontFamily="var(--font-mono)">
            {fmtDollar(lastB)}
          </text>
        )}
      </svg>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════
   DEFAULT DATE RANGE
   ═══════════════════════════════════════════════════════════════ */
function defaultDateRange() {
  const yesterday = new Date();
  yesterday.setDate(yesterday.getDate() - 1);
  const start = new Date(yesterday);
  start.setDate(start.getDate() - 65);
  const fmt = (d) => d.toISOString().slice(0, 10);
  return { start: fmt(start), end: fmt(yesterday) };
}

/* ═══════════════════════════════════════════════════════════════
   MAIN COMPONENT
   ═══════════════════════════════════════════════════════════════ */
export default function BacktestRunnerPage() {
  usePageTitle('Backtest Runner');
  const { regions: regionsArr } = useRegions();
  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);

  // Bot state
  const [bots, setBots] = useState([]);
  const [selectedBot, setSelectedBot] = useState('');

  // Form state
  const defaults = defaultDateRange();
  const [selectedStrategy, setSelectedStrategy] = useState('');
  const [region, setRegion] = useState('us');
  const [startDate, setStartDate] = useState(defaults.start);
  const [endDate, setEndDate] = useState(defaults.end);
  const [tradeMode, setTradeMode] = useState('shares');
  const [tradeSize, setTradeSize] = useState('100');
  const [commissionRate, setCommissionRate] = useState('0.001');

  // Portfolio simulation params
  const [capital, setCapital] = useState('10000');
  const [maxPositions, setMaxPositions] = useState('5');
  const [positionSizePct, setPositionSizePct] = useState('20');
  const [slippageBps, setSlippageBps] = useState('5');
  const [costsEnabled, setCostsEnabled] = useState(true);
  const [maxEntriesPerDay, setMaxEntriesPerDay] = useState('8');

  // Run state
  const [running, setRunning] = useState(false);
  const [progress, setProgress] = useState(null);
  const [results, setResults] = useState(null);
  const [error, setError] = useState(null);

  // Task queue state (AWS hybrid mode)
  const [taskId, setTaskId] = useState(null);
  const [taskStatus, setTaskStatus] = useState(null);
  const [workerHealth, setWorkerHealth] = useState(null);

  // Live equity from telemetry
  const [liveEquity, setLiveEquity] = useState(null);

  // Upgrade modal state
  const [upgradeModal, setUpgradeModal] = useState({ open: false, feature: null, detail: null, upgradeTier: null });

  // Active tab (single/batch/optimize)
  const [activeTab, setActiveTab] = useState('single');

  // Compare mode state
  const [compareMode, setCompareMode] = useState(false);
  const [compareStrategy, setCompareStrategy] = useState('');
  const [compareRunning, setCompareRunning] = useState(false);
  const [compareResults, setCompareResults] = useState(null);

  useEffect(() => {
    (async () => {
      const [stratData, telem, botData] = await Promise.all([
        api('/strategies'),
        api('/telemetry/latest'),
        api('/bots'),
      ]);
      if (botData?.bots) setBots(botData.bots);
      if (stratData) {
        const list = Array.isArray(stratData) ? stratData : stratData.strategies || [];
        setStrategies(list);
        if (list.length > 0 && !selectedStrategy) {
          const first = list[0];
          setSelectedStrategy(first.name || first.key || first.label || (typeof first === 'string' ? first : ''));
        }
      }
      if (telem) {
        let total = 0;
        const gw = telem.gateway || {};
        for (const [acct, data] of Object.entries(gw)) {
          if (acct === 'All') continue;
          const nlv = data?.net_liquidation || data?.equity?.current || 0;
          if (nlv > 0) total += nlv;
        }
        if (total > 0) setLiveEquity(total);
      }
      setLoading(false);
    })();
  }, []);

  // Poll progress when running (local mode)
  useEffect(() => {
    if (!running || taskId) return;
    const interval = setInterval(async () => {
      const status = await api('/backtest/status');
      if (status) {
        setProgress(status);
        if (status.phase === 'complete' || status.phase === 'done' || status.pct >= 100) {
          setRunning(false);
          const res = await api('/backtest/results');
          if (res) setResults(res);
        } else if (status.phase === 'failed' || status.phase === 'error') {
          setRunning(false);
          setError(status.error || 'Backtest failed');
        }
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [running, taskId]);

  // Poll task queue status (AWS hybrid mode)
  useEffect(() => {
    if (!taskId) return;
    const interval = setInterval(async () => {
      const status = await api(`/backtest/task/${taskId}`);
      if (status && !status.error) {
        setTaskStatus(status.status);
        const pct = parseInt(status.progress) || 0;
        setProgress({ pct, phase: status.status, current: status.type || 'backtest' });

        if (status.status === 'completed') {
          setRunning(false);
          setTaskId(null);
          const res = await api('/backtest/results');
          if (res) setResults(res);
        } else if (status.status === 'failed') {
          setRunning(false);
          setTaskId(null);
          setError(status.error || 'Task failed on compute worker');
        }
      }
    }, 3000);
    return () => clearInterval(interval);
  }, [taskId]);

  // Poll worker health
  useEffect(() => {
    const fetchHealth = async () => {
      const health = await api('/backtest/worker/health');
      if (health) setWorkerHealth(health);
    };
    fetchHealth();
    const interval = setInterval(fetchHealth, 30000);
    return () => clearInterval(interval);
  }, []);

  const handleRun = useCallback(async () => {
    // ── Gate checks ──
    const stratCheck = canUseStrategy(selectedStrategy);
    if (!stratCheck.allowed) {
      setUpgradeModal({ open: true, feature: 'strategy', detail: selectedStrategy, upgradeTier: stratCheck.reason });
      return;
    }
    // Check timeframe years
    if (startDate && endDate) {
      const days = Math.round((new Date(endDate) - new Date(startDate)) / 86400000);
      const years = days / 365.25;
      const tfCheck = canUseTimeframe(years);
      if (!tfCheck.allowed) {
        setUpgradeModal({ open: true, feature: 'timeframe', detail: `${years.toFixed(1)} years of data`, upgradeTier: tfCheck.reason });
        return;
      }
    }
    // Check remaining runs
    const runsCheck = getRemainingRuns();
    if (runsCheck.remaining <= 0) {
      setUpgradeModal({ open: true, feature: 'runs', detail: `${runsCheck.limit} runs used today`, upgradeTier: 'pro' });
      return;
    }
    recordRun();

    setError(null);
    setResults(null);
    setProgress(null);
    setTaskId(null);
    setTaskStatus(null);
    setRunning(true);
    const config = {
      strategy: selectedStrategy,
      region,
      start_date: startDate,
      end_date: endDate,
      trade_mode: tradeMode,
      trade_size: Number(tradeSize),
      commission_rate: Number(commissionRate),
      capital: Number(capital),
      max_positions: Number(maxPositions),
      position_size_pct: Number(positionSizePct),
      slippage_bps: Number(slippageBps),
      costs_enabled: costsEnabled,
      max_entries_per_day: Number(maxEntriesPerDay),
    };
    const res = await apiPost('/backtest/run', config);
    if (!res || res.error) {
      setError(res?.error || 'Failed to start backtest');
      setRunning(false);
    } else if (res.status === 'queued' && res.task_id) {
      setTaskId(res.task_id);
      setTaskStatus('queued');
      setProgress({ pct: 0, phase: 'queued', current: 'Waiting for compute worker...' });
    }
  }, [selectedStrategy, region, startDate, endDate, tradeMode, tradeSize, commissionRate, capital, maxPositions, positionSizePct, slippageBps, costsEnabled, maxEntriesPerDay]);

  const useLiveEquity = () => {
    if (liveEquity) setCapital(String(Math.round(liveEquity)));
  };

  // ── Compare Mode: run a second strategy backtest with same parameters ──
  const handleRunCompare = useCallback(async () => {
    if (!compareStrategy || compareStrategy === selectedStrategy) return;
    setCompareRunning(true);
    setCompareResults(null);
    const config = {
      strategy: compareStrategy,
      region,
      start_date: startDate,
      end_date: endDate,
      trade_mode: tradeMode,
      trade_size: Number(tradeSize),
      commission_rate: Number(commissionRate),
      capital: Number(capital),
      max_positions: Number(maxPositions),
      position_size_pct: Number(positionSizePct),
      slippage_bps: Number(slippageBps),
      costs_enabled: costsEnabled,
      max_entries_per_day: Number(maxEntriesPerDay),
    };
    const res = await apiPost('/backtest/run', config);
    if (!res || res.error) {
      setCompareRunning(false);
      return;
    }
    const pollCompare = async () => {
      for (let i = 0; i < 120; i++) {
        await new Promise(r => setTimeout(r, 2000));
        const status = await api('/backtest/status');
        if (status && (status.phase === 'complete' || status.phase === 'done' || status.pct >= 100)) {
          const cmpRes = await api('/backtest/results');
          setCompareResults(cmpRes);
          setCompareRunning(false);
          return;
        }
        if (status && (status.phase === 'failed' || status.phase === 'error')) {
          setCompareRunning(false);
          return;
        }
      }
      setCompareRunning(false);
    };
    pollCompare();
  }, [compareStrategy, selectedStrategy, region, startDate, endDate, tradeMode, tradeSize, commissionRate, capital, maxPositions, positionSizePct, slippageBps, costsEnabled, maxEntriesPerDay]);

  // Build compare equity curve from compare results
  const compareEquityCurve = useMemo(() => {
    if (!compareResults) return [];
    const cmpPerSignal = compareResults.per_signal || [];
    if (cmpPerSignal.length === 0) return [];
    const sorted = [...cmpPerSignal].filter(sig => sig.pnl != null).sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));
    let cum = 0;
    const curve = [];
    const sc = Number(capital) || 10000;
    const step = Math.max(1, Math.floor(sorted.length / 200));
    for (let i = 0; i < sorted.length; i += step) {
      for (let j = (i === 0 ? 0 : i - step + 1); j <= i && j < sorted.length; j++) {
        cum += sorted[j].pnl || 0;
      }
      curve.push(sc + cum);
    }
    return curve;
  }, [compareResults, capital]);

  // Filter strategies by selected bot
  const filteredStrategies = useMemo(() => {
    if (!selectedBot) return strategies;
    const bot = bots.find(b => b.bot_name === selectedBot);
    if (bot && bot.strategies && bot.strategies.length > 0) {
      const botStrats = new Set((bot.strategies || []).map(st => (st || '').toLowerCase()));
      return strategies.filter(st => {
        const name = st.name || st.key || st.label || (typeof st === 'string' ? st : '');
        return botStrats.has(name.toLowerCase());
      });
    }
    return strategies;
  }, [strategies, selectedBot, bots]);

  // Auto-select first strategy when filtered list changes
  useEffect(() => {
    if (filteredStrategies.length > 0 && !filteredStrategies.some(st => {
      const name = st.name || st.key || st.label || (typeof st === 'string' ? st : '');
      return name === selectedStrategy;
    })) {
      const first = filteredStrategies[0];
      setSelectedStrategy(first.name || first.key || first.label || (typeof first === 'string' ? first : ''));
    }
  }, [filteredStrategies]);

  const pct = progress?.pct || 0;
  const summary = results?.summary || results;

  // ── Derived analytics from per_signal data ──
  const startingCapital = Number(capital) || 10000;
  const perSignal = results?.per_signal || [];
  const btShares = results?.trade_config?.size || Number(tradeSize) || 100;

  // Timeframe from per_signal or form dates
  const timeframe = useMemo(() => {
    if (perSignal.length > 0) {
      let minDate = null, maxDate = null;
      for (const sig of perSignal) {
        const d = sig.signal_date;
        if (!d) continue;
        if (!minDate || d < minDate) minDate = d;
        if (!maxDate || d > maxDate) maxDate = d;
      }
      if (minDate && maxDate) {
        const totalDays = Math.max(1, Math.round((new Date(maxDate) - new Date(minDate)) / 86400000));
        return { dateFrom: minDate, dateTo: maxDate, totalDays };
      }
    }
    if (startDate && endDate) {
      const totalDays = Math.max(1, Math.round((new Date(endDate) - new Date(startDate)) / 86400000));
      return { dateFrom: startDate, dateTo: endDate, totalDays };
    }
    return { dateFrom: null, dateTo: null, totalDays: 0 };
  }, [perSignal, startDate, endDate]);

  // Scale per_signal PnL if needed and compute totals
  const scaledAnalytics = useMemo(() => {
    if (!summary) return null;

    if (summary.portfolio) {
      const p = summary.portfolio;
      const pnl = p.net_pnl || 0;
      const sc = p.starting_capital || startingCapital;
      const ending = sc + pnl;
      const ret = sc > 0 ? (pnl / sc) * 100 : 0;
      const cagrVal = computeCAGR(sc, ending, timeframe.totalDays);
      return { totalPnl: pnl, startingCapital: sc, endingEquity: ending, totalReturn: ret, cagr: cagrVal, isPortfolio: true };
    }

    if (perSignal.length > 0) {
      let totalPnl = 0;
      for (const sig of perSignal) totalPnl += sig.pnl || 0;
      const endingEquity = startingCapital + totalPnl;
      const totalReturn = startingCapital > 0 ? (totalPnl / startingCapital) * 100 : 0;
      const cagrVal = computeCAGR(startingCapital, endingEquity, timeframe.totalDays);
      return { totalPnl, startingCapital, endingEquity, totalReturn, cagr: cagrVal, isPortfolio: false };
    }

    const pnl = summary.netProfit || summary.net_profit || summary.total_pnl || 0;
    const endingEquity = startingCapital + pnl;
    const totalReturn = startingCapital > 0 ? (pnl / startingCapital) * 100 : 0;
    const cagrVal = computeCAGR(startingCapital, endingEquity, timeframe.totalDays);
    return { totalPnl: pnl, startingCapital, endingEquity, totalReturn, cagr: cagrVal, isPortfolio: false };
  }, [summary, perSignal, startingCapital, timeframe]);

  const totalSignals = results?.total_signals || perSignal.length ||
    (summary?.portfolio ? summary.portfolio.trades_executed + (summary.portfolio.trades_skipped || 0) : 0);

  // Equity curve from per_signal
  const equityCurve = useMemo(() => {
    if (perSignal.length === 0) return [];
    const sorted = [...perSignal].filter(sig => sig.pnl != null).sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));
    let cum = 0;
    const curve = [];
    const step = Math.max(1, Math.floor(sorted.length / 200));
    for (let i = 0; i < sorted.length; i += step) {
      for (let j = (i === 0 ? 0 : i - step + 1); j <= i && j < sorted.length; j++) {
        cum += sorted[j].pnl || 0;
      }
      curve.push(startingCapital + cum);
    }
    return curve;
  }, [perSignal, startingCapital]);

  // Annual breakdown from per_signal
  const annualData = useMemo(() => {
    if (perSignal.length === 0) return [];
    const sorted = [...perSignal]
      .filter(sig => sig.pnl != null && sig.signal_date)
      .sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));

    const byYear = {};
    for (const sig of sorted) {
      const year = parseInt(sig.signal_date.slice(0, 4));
      if (!byYear[year]) byYear[year] = { year, pnl: 0, trades: 0, wins: 0 };
      byYear[year].pnl += sig.pnl || 0;
      byYear[year].trades++;
      const dir = sig.direction || 'long';
      const ret = sig.post_return || 0;
      const isWin = (dir === 'long' && ret > 0) || (dir === 'short' && ret < 0);
      if (isWin) byYear[year].wins++;
    }

    const years = Object.values(byYear).sort((a, b) => a.year - b.year);
    let runningEquity = startingCapital;
    for (const y of years) {
      y.startEquity = runningEquity;
      y.winRate = y.trades > 0 ? (y.wins / y.trades) * 100 : 0;
      y.pnl = Math.round(y.pnl);
      runningEquity += y.pnl;
    }
    return years;
  }, [perSignal, startingCapital]);

  // By-strategy breakdown from per_signal
  const byStrategy = useMemo(() => {
    if (perSignal.length === 0) return {};
    const map = {};
    for (const sig of perSignal) {
      const strat = sig.strategy || 'Unknown';
      if (!map[strat]) map[strat] = { count: 0, wins: 0, pnl: 0, direction: sig.direction || 'long' };
      map[strat].count++;
      map[strat].pnl += sig.pnl || 0;
      const dir = sig.direction || 'long';
      const ret = sig.post_return || 0;
      if ((dir === 'long' && ret > 0) || (dir === 'short' && ret < 0)) map[strat].wins++;
    }
    return map;
  }, [perSignal]);

  const numStrategies = Object.keys(byStrategy).length || 1;
  const allocatedCapitalPerStrategy = startingCapital / numStrategies;

  const strategyRows = useMemo(() => {
    return Object.entries(byStrategy)
      .map(([name, st]) => {
        const stratReturn = allocatedCapitalPerStrategy > 0 ? (st.pnl / allocatedCapitalPerStrategy) * 100 : 0;
        const winRate = st.count > 0 ? (st.wins / st.count) * 100 : 0;
        return { name, count: st.count, winRate, pnl: st.pnl, stratReturn, direction: st.direction };
      })
      .sort((a, b) => b.pnl - a.pnl);
  }, [byStrategy, allocatedCapitalPerStrategy]);

  // Advanced metrics
  const advancedMetrics = useMemo(() => {
    if (perSignal.length === 0) return { sharpe: null, maxDD: 0, maxDDPct: 0, winRate: 0, winStreak: 0, loseStreak: 0, longs: 0, shorts: 0 };
    const sorted = [...perSignal].filter(sig => sig.pnl != null).sort((a, b) => (a.signal_date || '').localeCompare(b.signal_date || ''));
    let peak = 0, cum = 0, maxDD = 0, peakEquity = 0, wins = 0, curW = 0, curL = 0, bestW = 0, worstL = 0, longs = 0, shorts = 0;
    const rets = [];
    for (const sig of sorted) {
      const pnl = sig.pnl || 0;
      const dir = sig.direction || 'long';
      const ret = sig.post_return || 0;
      const isWin = (dir === 'long' && ret > 0) || (dir === 'short' && ret < 0);
      cum += pnl;
      if (cum > peak) peak = cum;
      const dd = peak - cum;
      if (dd > maxDD) maxDD = dd;
      const pv = startingCapital + cum;
      if (pv > peakEquity) peakEquity = pv;
      rets.push(pnl);
      if (dir === 'long') longs++; else shorts++;
      if (isWin) { wins++; curW++; curL = 0; if (curW > bestW) bestW = curW; }
      else { curL++; curW = 0; if (curL > worstL) worstL = curL; }
    }
    const maxDDPct = peakEquity > 0 ? (maxDD / peakEquity * 100) : 0;
    let sharpe = null;
    if (rets.length > 1) {
      const mean = rets.reduce((a, b) => a + b, 0) / rets.length;
      const std = Math.sqrt(rets.reduce((a, b) => a + (b - mean) ** 2, 0) / (rets.length - 1));
      if (std > 0) sharpe = (mean / std) * Math.sqrt(252);
    }
    return { sharpe, maxDD, maxDDPct, winRate: sorted.length > 0 ? wins / sorted.length * 100 : 0, winStreak: bestW, loseStreak: worstL, longs, shorts };
  }, [perSignal, startingCapital]);

  // ── Tier-aware helpers ──
  const userTier = getUserTier();
  const isPro = TIER_LEVELS[userTier] >= TIER_LEVELS.pro;
  const isTrader = TIER_LEVELS[userTier] >= TIER_LEVELS.trader;
  const btConfig = getBacktestConfig();
  const runsInfo = getRemainingRuns();

  // ── Timeframe presets ──
  const TIMEFRAME_PRESETS = [
    { label: '1Y', years: 1 },
    { label: '2Y', years: 2 },
    { label: '5Y', years: 5 },
    { label: '10Y', years: 10 },
    { label: '20Y', years: 20 },
    { label: '30Y', years: 30 },
  ];

  const applyTimeframePreset = (years) => {
    const check = canUseTimeframe(years);
    if (!check.allowed) {
      setUpgradeModal({ open: true, feature: 'timeframe', detail: `${years} years of historical data`, upgradeTier: check.reason });
      return;
    }
    const end = new Date();
    end.setDate(end.getDate() - 1);
    const start = new Date(end);
    start.setFullYear(start.getFullYear() - years);
    setStartDate(start.toISOString().slice(0, 10));
    setEndDate(end.toISOString().slice(0, 10));
  };

  // ── Progress label from pct ──
  const progressLabel = useMemo(() => {
    const p = progress?.pct || 0;
    if (p < 30) return 'Running backtest...';
    if (p < 60) return 'Analyzing price data...';
    if (p < 90) return 'Evaluating signals...';
    return 'Computing results...';
  }, [progress]);

  return (
    <div className={s.page}>
      {/* Upgrade Modal */}
      <BacktestUpgradeModal
        open={upgradeModal.open}
        onClose={() => setUpgradeModal({ open: false, feature: null, detail: null, upgradeTier: null })}
        feature={upgradeModal.feature}
        detail={upgradeModal.detail}
        upgradeTier={upgradeModal.upgradeTier}
      />

      <LoadingState loading={loading} error={error} empty={false} type='table'>
        <>
          <h1 className={s.pageTitle}>Backtest Runner</h1>
          <p className={s.pageSubtitle}>Validate signal systems against historical data before deploying capital</p>

          {/* ── Mode Tabs: Single / Batch / Optimize ── */}
          <div className={s.tabRow}>
            <button
              className={activeTab === 'single' ? s.tabActive : s.tab}
              onClick={() => setActiveTab('single')}
            >
              Single Run
            </button>
            <button
              className={activeTab === 'batch' ? s.tabActive : s.tab}
              onClick={() => {
                const check = canRunBatch();
                if (!check.allowed) {
                  setUpgradeModal({ open: true, feature: 'batch', detail: null, upgradeTier: check.reason });
                  return;
                }
                setActiveTab('batch');
              }}
            >
              {!isPro && (
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ marginRight: 4, verticalAlign: -1, opacity: 0.6 }}>
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0110 0v4" />
                </svg>
              )}
              Batch Testing
            </button>
            <button
              className={activeTab === 'optimize' ? s.tabActive : s.tab}
              onClick={() => {
                const check = canOptimize();
                if (!check.allowed) {
                  setUpgradeModal({ open: true, feature: 'optimize', detail: null, upgradeTier: check.reason });
                  return;
                }
                setActiveTab('optimize');
              }}
            >
              {!isPro && (
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ marginRight: 4, verticalAlign: -1, opacity: 0.6 }}>
                  <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                  <path d="M7 11V7a5 5 0 0110 0v4" />
                </svg>
              )}
              Optimization
            </button>
          </div>

          {/* Configuration Form */}
          <div className={s.configCard}>
            <div className={s.configTitle}>Configuration</div>

            <div className={s.gridFour}>
              <div>
                <label className={s.label}>Bot</label>
                <select
                  value={selectedBot}
                  onChange={(e) => { setSelectedBot(e.target.value); setSelectedStrategy(''); }}
                  disabled={running}
                  className={running ? s.selectDisabled : s.selectPointer}
                >
                  <option value="">All Bots</option>
                  {bots.map(b => (
                    <option key={b.bot_name} value={b.bot_name}>
                      {(b.display_name || b.bot_name).toUpperCase()}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className={s.label}>Strategy</label>
                <select
                  value={selectedStrategy}
                  onChange={(e) => {
                    const val = e.target.value;
                    const check = canUseStrategy(val);
                    if (!check.allowed) {
                      setUpgradeModal({ open: true, feature: 'strategy', detail: val, upgradeTier: check.reason });
                      return;
                    }
                    setSelectedStrategy(val);
                  }}
                  disabled={running}
                  className={running ? s.selectDisabled : s.selectPointer}
                >
                  {loading ? (
                    <option>Loading strategies...</option>
                  ) : filteredStrategies.length === 0 ? (
                    <option>No strategies available</option>
                  ) : (
                    filteredStrategies.map((st, i) => {
                      const name = st.name || st.key || st.label || (typeof st === 'string' ? st : `Strategy ${i + 1}`);
                      const normalized = (name || '').toLowerCase().replace(/[\s\-]+/g, '_');
                      const locked = !isPro && !FREE_STRATEGIES.includes(normalized);
                      return (
                        <option key={name || i} value={name}>
                          {locked ? '\u{1F512} ' : ''}{st.label || name}
                        </option>
                      );
                    })
                  )}
                </select>
              </div>
              <div>
                <label className={s.label}>Region</label>
                <select value={region} onChange={(e) => setRegion(e.target.value)} disabled={running} className={running ? s.selectDisabled : s.selectPointer}>
                  {regionsArr.map((r) => (
                    <option key={r.key} value={r.key}>{r.label}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className={s.label}>Trade Sizing</label>
                <div className={s.tradeSizeRow}>
                  <select value={tradeMode} onChange={(e) => { setTradeMode(e.target.value); setTradeSize(e.target.value === 'shares' ? '100' : '10000'); }} disabled={running} className={running ? s.selectDisabled : s.tradeModeSelect}>
                    <option value="shares">Shares</option>
                    <option value="dollars">Dollars</option>
                  </select>
                  <input type="number" value={tradeSize} onChange={(e) => setTradeSize(e.target.value)} disabled={running} className={s.tradeSizeInput} placeholder={tradeMode === 'shares' ? '100' : '10000'} />
                </div>
              </div>
            </div>

            <div className={s.gridThree}>
              <div>
                <label className={s.label}>Start Date</label>
                <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} disabled={running} className={s.input} />
              </div>
              <div>
                <label className={s.label}>End Date</label>
                <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} disabled={running} className={s.input} />
              </div>
              <div>
                <label className={s.label}>Commission Rate</label>
                <input type="number" step="0.0001" value={commissionRate} onChange={(e) => setCommissionRate(e.target.value)} disabled={running} className={s.input} />
              </div>
            </div>

            {/* Timeframe Presets */}
            <div className={s.timeframePresets}>
              <span className={s.presetLabel}>Quick range:</span>
              {TIMEFRAME_PRESETS.map(({ label, years }) => {
                const locked = years > btConfig.maxYears;
                return (
                  <button
                    key={label}
                    onClick={() => applyTimeframePreset(years)}
                    disabled={running}
                    className={locked ? s.presetBtnLocked : s.presetBtn}
                    title={locked ? `Requires ${years > 5 ? 'Pro' : 'Trader'} tier` : `Set range to ${years} year${years > 1 ? 's' : ''}`}
                  >
                    {locked && (
                      <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" style={{ marginRight: 3, verticalAlign: -1, opacity: 0.5 }}>
                        <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                        <path d="M7 11V7a5 5 0 0110 0v4" />
                      </svg>
                    )}
                    {label}
                  </button>
                );
              })}
            </div>

            {/* Portfolio Simulation Config */}
            <div className={s.portfolioSection}>
              <div className={s.portfolioHeader}>
                <span className={s.portfolioTitle}>Portfolio Simulation</span>
                <label className={s.toggleRow}>
                  <span className={s.toggleLabel} style={{ color: costsEnabled ? C.green : C.textSecondary }}>
                    {costsEnabled ? 'COSTS ON' : 'COSTS OFF'}
                  </span>
                  <div
                    onClick={() => !running && setCostsEnabled(!costsEnabled)}
                    className={s.toggleTrack}
                    style={{
                      background: costsEnabled ? C.green : C.surface2,
                      border: `1px solid ${costsEnabled ? C.green : C.border}`,
                      cursor: running ? 'not-allowed' : 'pointer',
                    }}
                  >
                    <div className={s.toggleThumb} style={{ left: costsEnabled ? 18 : 2 }} />
                  </div>
                </label>
              </div>
              <div className={s.gridFour}>
                <div>
                  <label className={s.label}>
                    Starting Capital ($)
                    {liveEquity && (
                      <span className={s.liveEquityLink} onClick={useLiveEquity}>
                        Live: ${liveEquity.toLocaleString(undefined, { maximumFractionDigits: 0 })}
                      </span>
                    )}
                  </label>
                  <input type="number" step="1" value={capital} onChange={(e) => setCapital(e.target.value)} disabled={running} className={s.input} placeholder="10000" />
                </div>
                <div>
                  <label className={s.label}>Max Positions</label>
                  <input type="number" min="1" max="50" value={maxPositions} onChange={(e) => setMaxPositions(e.target.value)} disabled={running} className={s.input} />
                </div>
                <div>
                  <label className={s.label}>Position Size (%)</label>
                  <input type="number" min="1" max="100" step="1" value={positionSizePct} onChange={(e) => setPositionSizePct(e.target.value)} disabled={running} className={s.input} />
                </div>
                <div>
                  <label className={s.label}>Slippage (bps)</label>
                  <input type="number" min="0" max="100" step="1" value={slippageBps} onChange={(e) => setSlippageBps(e.target.value)} disabled={running} className={s.input} />
                </div>
              </div>
            </div>

            {/* Run button row with remaining indicator */}
            <div className={s.runRow}>
              <button
                onClick={handleRun}
                disabled={running || !selectedStrategy}
                className={running || !selectedStrategy ? s.runBtnDisabled : s.runBtnActive}
              >
                {running ? `Running... ${pct}%` : 'Run Backtest'}
              </button>
              {!isPro && (
                <span className={s.runsRemaining}>
                  {runsInfo.remaining} of {runsInfo.limit} backtests remaining today
                </span>
              )}
            </div>
          </div>

          {/* ── Animated Progress ── */}
          {running && (
            <div className={s.progressCard}>
              <div className={s.progressBarTrack}>
                <div className={s.progressBarFill} style={{ width: `${pct}%`, background: `linear-gradient(90deg, ${C.blue}, ${C.purple})` }} />
              </div>
              <div className={s.progressLabel}>
                <span className={s.progressDot} />
                {progressLabel}
              </div>
              <div className={s.progressPct}>{pct}%</div>
            </div>
          )}

          {/* Results Section */}
          {results && (
            <>
              <TimeframeBanner dateFrom={timeframe.dateFrom} dateTo={timeframe.dateTo} totalDays={timeframe.totalDays} />
              <CapitalSummaryCard
                startingCapital={scaledAnalytics?.startingCapital || startingCapital}
                endingEquity={scaledAnalytics?.endingEquity || startingCapital}
                totalReturn={scaledAnalytics?.totalReturn || 0}
                cagr={scaledAnalytics?.cagr || 0}
                totalDays={timeframe.totalDays}
              />
              {/* Key Performance Metrics */}
              <div className={s.metricsRow}>
                <StatCard
                  label="Sharpe Ratio"
                  value={advancedMetrics.sharpe != null ? advancedMetrics.sharpe.toFixed(2) : '\u2014'}
                  accent={advancedMetrics.sharpe != null ? (advancedMetrics.sharpe >= 1 ? C.green : advancedMetrics.sharpe >= 0.5 ? C.amber : C.red) : C.textSecondary}
                  sub={advancedMetrics.sharpe != null ? (advancedMetrics.sharpe >= 2 ? 'Excellent' : advancedMetrics.sharpe >= 1 ? 'Good' : advancedMetrics.sharpe >= 0.5 ? 'Average' : 'Poor') : null}
                />
                <StatCard
                  label="Win Rate"
                  value={fmtPct(advancedMetrics.winRate)}
                  accent={advancedMetrics.winRate >= 55 ? C.green : advancedMetrics.winRate >= 45 ? C.amber : C.red}
                  sub={`${(totalSignals || 0).toLocaleString()} trades`}
                />
                <StatCard
                  label="Max Drawdown"
                  value={advancedMetrics.maxDDPct > 0 ? `-${advancedMetrics.maxDDPct.toFixed(1)}%` : '\u2014'}
                  accent={advancedMetrics.maxDDPct < 10 ? C.green : advancedMetrics.maxDDPct < 20 ? C.amber : C.red}
                  sub={advancedMetrics.maxDD > 0 ? fmtDollarSigned(-advancedMetrics.maxDD) : null}
                />
                <StatCard
                  label="Profit Factor"
                  value={(() => {
                    const p = summary?.portfolio || summary;
                    const pfVal = p?.profit_factor ?? p?.profitFactor;
                    if (pfVal != null && isFinite(pfVal)) return pfVal >= 50 ? '\u221E' : pfVal.toFixed(2);
                    return '\u2014';
                  })()}
                  accent={(() => {
                    const p = summary?.portfolio || summary;
                    const pfVal = p?.profit_factor ?? p?.profitFactor;
                    return pfColor(pfVal);
                  })()}
                />
                <StatCard
                  label="Best Streak"
                  value={`${advancedMetrics.winStreak}W / ${advancedMetrics.loseStreak}L`}
                  accent={C.textPrimary}
                  sub={`${advancedMetrics.longs}L / ${advancedMetrics.shorts}S`}
                />
              </div>

              <PositionSizingCard
                tradeMode={tradeMode}
                positionSizePct={Number(positionSizePct)}
                startingCapital={startingCapital}
                maxPositions={Number(maxPositions)}
                slippageBps={Number(slippageBps)}
                costsEnabled={costsEnabled}
              />
              <TradeCountWarning totalTrades={totalSignals} totalDays={timeframe.totalDays} />
              <EquityCurveSVG data={equityCurve} startVal={startingCapital} />
              <AnnualBreakdownTable annualData={annualData} />

              {/* ExportBar for perSignal data */}
              <ExportBar data={perSignal} filename='export' />

              {/* Strategy table */}
              <div className={s.resultsTable}>
                <table className={s.table}>
                  <thead>
                    <tr>
                      <th className={s.th}>Strategy</th>
                      <th className={s.thRight}>Trades</th>
                      <th className={s.thRight}>Win Rate</th>
                      <th className={s.thRight}>PnL</th>
                      <th className={s.thRight}>Return</th>
                    </tr>
                  </thead>
                  <tbody>
                    {strategyRows.map(row => (
                      <tr key={row.name} style={{ borderBottom: `1px solid ${C.border}` }}>
                        <td className={s.td}>{row.name}</td>
                        <td className={s.tdRight}>{(row.count || 0).toLocaleString()}</td>
                        <td className={s.tdRight} style={{ color: pfColor(row.winRate) }}>{fmtPct(row.winRate)}</td>
                        <td className={s.tdRight} style={{ color: row.pnl >= 0 ? C.green : C.red }}>{fmtDollarSigned(row.pnl)}</td>
                        <td className={s.tdRight} style={{ color: row.stratReturn >= 0 ? C.green : C.red }}>{fmtPct(row.stratReturn)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              {/* Compare Mode */}
              <div className={s.compareCard}>
                <div className={s.compareHeader}>
                  <div className={s.compareTitle}>Compare Strategies</div>
                  <label className={s.toggleRow}>
                    <span className={s.toggleLabel} style={{ color: compareMode ? C.purple : C.textSecondary }}>
                      {compareMode ? 'COMPARE ON' : 'COMPARE OFF'}
                    </span>
                    <div
                      onClick={() => setCompareMode(!compareMode)}
                      className={s.toggleTrack}
                      style={{
                        background: compareMode ? C.purple : C.surface2,
                        border: `1px solid ${compareMode ? C.purple : C.border}`,
                        cursor: 'pointer',
                      }}
                    >
                      <div className={s.toggleThumb} style={{ left: compareMode ? 18 : 2 }} />
                    </div>
                  </label>
                </div>

                {compareMode && (
                  <>
                    <div className={s.compareFormRow}>
                      <div className={s.compareFormLeft}>
                        <label className={s.label}>Compare Against</label>
                        <select
                          value={compareStrategy}
                          onChange={(e) => setCompareStrategy(e.target.value)}
                          disabled={compareRunning}
                          className={compareRunning ? s.selectDisabled : s.selectPointer}
                        >
                          <option value="">Select a strategy...</option>
                          {filteredStrategies
                            .filter(st => {
                              const name = st.name || st.key || st.label || (typeof st === 'string' ? st : '');
                              return name !== selectedStrategy;
                            })
                            .map((st, i) => {
                              const name = st.name || st.key || st.label || (typeof st === 'string' ? st : `Strategy ${i + 1}`);
                              return <option key={name || i} value={name}>{st.label || name}</option>;
                            })}
                        </select>
                      </div>
                      <button
                        onClick={handleRunCompare}
                        disabled={compareRunning || !compareStrategy || compareStrategy === selectedStrategy}
                        className={compareRunning || !compareStrategy ? s.compareBtnDisabled : s.compareBtnActive}
                      >
                        {compareRunning ? 'Running...' : 'Run Comparison'}
                      </button>
                    </div>

                    <div className={s.compareHint}>
                      Uses the same region, date range, and portfolio settings as the primary backtest.
                    </div>

                    {/* Overlay Chart: both equity curves */}
                    {compareResults && equityCurve.length > 0 && (
                      <CompareEquityCurveSVG
                        dataA={equityCurve}
                        dataB={compareEquityCurve}
                        labelA={selectedStrategy}
                        labelB={compareStrategy}
                        startVal={startingCapital}
                      />
                    )}

                    {/* Side-by-side metrics comparison */}
                    {compareResults && (
                      <div className={s.compareGrid}>
                        {/* Primary strategy summary */}
                        <div className={s.compareSummary} style={{ border: `1px solid ${C.blue}30` }}>
                          <div className={s.compareSummaryName} style={{ color: C.blue }}>
                            {selectedStrategy}
                          </div>
                          <div className={s.compareSummaryGrid}>
                            <div>
                              <div className={s.compareMetricLabel}>Return</div>
                              <div className={s.compareMetricValue} style={{ color: (scaledAnalytics?.totalReturn || 0) >= 0 ? C.green : C.red }}>
                                {fmtPct(scaledAnalytics?.totalReturn || 0)}
                              </div>
                            </div>
                            <div>
                              <div className={s.compareMetricLabel}>Sharpe</div>
                              <div className={s.compareMetricValue} style={{ color: C.textPrimary }}>
                                {advancedMetrics.sharpe != null ? advancedMetrics.sharpe.toFixed(2) : '\u2014'}
                              </div>
                            </div>
                            <div>
                              <div className={s.compareMetricLabel}>Win Rate</div>
                              <div className={s.compareMetricValue} style={{ color: C.textPrimary }}>
                                {fmtPct(advancedMetrics.winRate)}
                              </div>
                            </div>
                            <div>
                              <div className={s.compareMetricLabel}>Max DD</div>
                              <div className={s.compareMetricValue} style={{ color: C.red }}>
                                {advancedMetrics.maxDDPct > 0 ? `-${advancedMetrics.maxDDPct.toFixed(1)}%` : '\u2014'}
                              </div>
                            </div>
                          </div>
                        </div>

                        {/* Compare strategy summary */}
                        {(() => {
                          const cmpPS = compareResults.per_signal || [];
                          const cmpSC = Number(capital) || 10000;
                          let cmpPnl = 0;
                          for (const sig of cmpPS) cmpPnl += sig.pnl || 0;
                          const cmpReturn = cmpSC > 0 ? (cmpPnl / cmpSC) * 100 : 0;

                          const rets = cmpPS.filter(sig => sig.pnl != null).map(sig => sig.pnl);
                          let cmpSharpe = null;
                          if (rets.length > 1) {
                            const mean = rets.reduce((a, b) => a + b, 0) / rets.length;
                            const std = Math.sqrt(rets.reduce((a, b) => a + (b - mean) ** 2, 0) / (rets.length - 1));
                            if (std > 0) cmpSharpe = (mean / std) * Math.sqrt(252);
                          }

                          let winsC = 0;
                          const sortedC = cmpPS.filter(sig => sig.pnl != null);
                          for (const sig of sortedC) {
                            const dir = sig.direction || 'long';
                            const ret = sig.post_return || 0;
                            if ((dir === 'long' && ret > 0) || (dir === 'short' && ret < 0)) winsC++;
                          }
                          const cmpWR = sortedC.length > 0 ? (winsC / sortedC.length) * 100 : 0;

                          let peakC = 0, cumC = 0, maxDDC = 0, peakEqC = 0;
                          for (const sig of sortedC) {
                            cumC += sig.pnl || 0;
                            if (cumC > peakC) peakC = cumC;
                            const dd = peakC - cumC;
                            if (dd > maxDDC) maxDDC = dd;
                            const pv = cmpSC + cumC;
                            if (pv > peakEqC) peakEqC = pv;
                          }
                          const cmpDDPct = peakEqC > 0 ? (maxDDC / peakEqC * 100) : 0;

                          return (
                            <div className={s.compareSummary} style={{ border: `1px solid ${C.purple}30` }}>
                              <div className={s.compareSummaryName} style={{ color: C.purple }}>
                                {compareStrategy}
                              </div>
                              <div className={s.compareSummaryGrid}>
                                <div>
                                  <div className={s.compareMetricLabel}>Return</div>
                                  <div className={s.compareMetricValue} style={{ color: cmpReturn >= 0 ? C.green : C.red }}>
                                    {fmtPct(cmpReturn)}
                                  </div>
                                </div>
                                <div>
                                  <div className={s.compareMetricLabel}>Sharpe</div>
                                  <div className={s.compareMetricValue} style={{ color: C.textPrimary }}>
                                    {cmpSharpe != null ? cmpSharpe.toFixed(2) : '\u2014'}
                                  </div>
                                </div>
                                <div>
                                  <div className={s.compareMetricLabel}>Win Rate</div>
                                  <div className={s.compareMetricValue} style={{ color: C.textPrimary }}>
                                    {fmtPct(cmpWR)}
                                  </div>
                                </div>
                                <div>
                                  <div className={s.compareMetricLabel}>Max DD</div>
                                  <div className={s.compareMetricValue} style={{ color: C.red }}>
                                    {cmpDDPct > 0 ? `-${cmpDDPct.toFixed(1)}%` : '\u2014'}
                                  </div>
                                </div>
                              </div>
                            </div>
                          );
                        })()}
                      </div>
                    )}
                  </>
                )}
              </div>

              {/* ── Deployment CTA Banner ── */}
              <div className={s.deployCta}>
                <div className={s.deployCtaInner}>
                  <div>
                    <div className={s.deployCtaTitle}>
                      This is standalone performance. Deploy this strategy live to compound real capital.
                    </div>
                    <div className={s.deployCtaSub}>
                      Paper trade first to validate in current market conditions, then go live.
                    </div>
                  </div>
                  <Link to="/paper-trading" className={s.deployCtaBtn}>
                    Start Paper Trading This Strategy
                  </Link>
                </div>
              </div>

              {/* ── Free tier persistent upgrade banner ── */}
              {!isPro && (
                <div className={s.upgradeBanner}>
                  <div className={s.upgradeBannerInner}>
                    <div className={s.upgradeBannerText}>
                      <strong>Unlock full backtesting</strong> — all 83 strategies, 30 years of data, batch testing, parameter optimization
                    </div>
                    <Link to="/pricing-plans" className={s.upgradeBannerBtn}>
                      Upgrade to Pro
                    </Link>
                  </div>
                </div>
              )}
            </>
          )}
        </>
      </LoadingState>
    </div>
  );
}
